<script>
(function() {
  // CLOCK
  function updateClock() {
    const now = new Date();
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    const ss = String(now.getSeconds()).padStart(2, '0');
    document.getElementById('clock').textContent = `${hh}:${mm}:${ss}`;
  }
  updateClock();
  setInterval(updateClock, 1000);

  // PERIOD TOGGLE
  const periodToggle = document.getElementById('periodToggle');
  const inactiveClass = 'px-3 py-1.5 text-xs font-medium text-slate-600 rounded-md hover:text-slate-900 transition';
  const activeClass = 'px-3 py-1.5 text-xs font-medium bg-rose-500 text-white rounded-md shadow-sm';
  periodToggle.addEventListener('click', e => {
    if (e.target.tagName !== 'BUTTON') return;
    periodToggle.querySelectorAll('button').forEach(b => b.className = inactiveClass);
    e.target.className = activeClass;
  });

  // LINE CHART
  const lineData = [3.2, 3.5, 4.0, 4.8, 5.2, 4.5, 6.8, 3.5, 3.8, 4.5, 4.2, 5.5, 5.8, 5.2, 4.5, 4.8, 5.0, 5.5, 5.8, 5.2, 4.5, 4.2, 4.8, 5.0, 5.5, 6.0, 5.5, 4.5, 4.2, 4.0, 4.5];

  function smoothPath(pts) {
    if (pts.length < 2) return '';
    let p = `M ${pts[0].x.toFixed(1)} ${pts[0].y.toFixed(1)}`;
    for (let i = 1; i < pts.length - 1; i++) {
      const midX = (pts[i].x + pts[i+1].x) / 2;
      const midY = (pts[i].y + pts[i+1].y) / 2;
      p += ` Q ${pts[i].x.toFixed(1)} ${pts[i].y.toFixed(1)} ${midX.toFixed(1)} ${midY.toFixed(1)}`;
    }
    p += ` T ${pts[pts.length-1].x.toFixed(1)} ${pts[pts.length-1].y.toFixed(1)}`;
    return p;
  }

  function renderLineChart() {
    const w = 720, h = 280;
    const padL = 36, padR = 16, padT = 16, padB = 30;
    const innerW = w - padL - padR;
    const innerH = h - padT - padB;
    const yMax = 8;
    const xScale = i => padL + (i / 30) * innerW;
    const yScale = v => padT + (1 - v / yMax) * innerH;

    const points = lineData.map((v, i) => ({ x: xScale(i), y: yScale(v) }));
    const linePath = smoothPath(points);
    const areaPath = `${linePath} L ${xScale(30).toFixed(1)} ${yScale(0).toFixed(1)} L ${xScale(0).toFixed(1)} ${yScale(0).toFixed(1)} Z`;

    let svg = `<svg viewBox="0 0 ${w} ${h}" class="w-full h-auto" preserveAspectRatio="none" style="font-family:Inter,sans-serif">`;
    svg += `<defs><linearGradient id="areaGrad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#f43f5e" stop-opacity="0.28"/><stop offset="100%" stop-color="#f43f5e" stop-opacity="0"/></linearGradient></defs>`;

    for (let i = 0; i <= 8; i++) {
      const y = yScale(i);
      svg += `<line x1="${padL}" y1="${y}" x2="${w - padR}" y2="${y}" stroke="#f1f5f9" stroke-width="1"/>`;
      svg += `<text x="${padL - 6}" y="${y + 3}" text-anchor="end" font-size="10" fill="#94a3b8" font-family="JetBrains Mono">${i}%</text>`;
    }

    [1, 4, 7, 10, 13, 16, 19, 22, 25, 28, 31].forEach(d => {
      const x = xScale(d - 1);
      svg += `<text x="${x}" y="${h - 8}" text-anchor="middle" font-size="10" fill="#94a3b8" font-family="JetBrains Mono">D${String(d).padStart(2, '0')}</text>`;
    });

    svg += `<path d="${areaPath}" fill="url(#areaGrad)"/>`;

    const objetivoY = yScale(5);
    svg += `<line x1="${padL}" y1="${objetivoY}" x2="${w - padR}" y2="${objetivoY}" stroke="#10b981" stroke-width="1.5" stroke-dasharray="4 4"/>`;
    svg += `<text x="${w - padR - 4}" y="${objetivoY - 5}" text-anchor="end" font-size="9" fill="#10b981" font-weight="700" font-family="Inter">5% objetivo</text>`;

    svg += `<path d="${linePath}" fill="none" stroke="#f43f5e" stroke-width="2.2" stroke-linejoin="round" stroke-linecap="round"/>`;

    [6, 12, 19, 25].forEach(i => {
      svg += `<circle cx="${xScale(i).toFixed(1)}" cy="${yScale(lineData[i]).toFixed(1)}" r="3.5" fill="#fff" stroke="#f43f5e" stroke-width="2"/>`;
    });

    [7, 14, 21, 28].forEach(d => {
      const x = xScale(d - 1);
      const y = yScale(lineData[d-1]);
      svg += `<line x1="${x.toFixed(1)}" y1="${padT}" x2="${x.toFixed(1)}" y2="${(y - 8).toFixed(1)}" stroke="#e2e8f0" stroke-width="1" stroke-dasharray="2 2" opacity="0.6"/>`;
    });

    svg += `</svg>`;
    document.getElementById('lineChart').innerHTML = svg;
  }
  renderLineChart();

  // DONUT
  const donutData = [
    { name: 'FRANCES', value: 3092, color: '#f43f5e', dot: '#dc2626' },
    { name: 'BIZCOCHO', value: 1855, color: '#f59e0b', dot: '#d97706' },
    { name: 'PASTELERIA', value: 1237, color: '#10b981', dot: '#059669' }
  ];
  function renderDonut() {
    const cx = 100, cy = 100, r = 70, sw = 22;
    let svg = `<svg viewBox="0 0 200 200" class="w-44 h-44">`;
    let offset = 0;
    donutData.forEach(d => {
      const dash = (d.value / 6184) * 100;
      const gap = 100 - dash;
      svg += `<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${d.color}" stroke-width="${sw}" pathLength="100" stroke-dasharray="${dash.toFixed(2)} ${gap.toFixed(2)}" stroke-dashoffset="${(-offset).toFixed(2)}" transform="rotate(-90 ${cx} ${cy})"/>`;
      offset += dash;
    });
    svg += `<text x="${cx}" y="${cy + 7}" text-anchor="middle" font-size="24" font-weight="700" fill="#0f172a" font-family="JetBrains Mono">6,184</text>`;
    svg += `</svg>`;
    document.getElementById('donutChart').innerHTML = svg;

    document.getElementById('donutLegend').innerHTML = donutData.map(d => `
      <div class="flex items-center justify-between text-xs">
        <div class="flex items-center gap-2">
          <span class="w-2 h-2 rounded-full" style="background:${d.dot}"></span>
          <span class="text-slate-600 font-semibold tracking-wider text-[10px]">${d.name}</span>
        </div>
        <span class="font-bold text-slate-900" style="font-family:'JetBrains Mono',monospace">${d.value.toLocaleString()} <span class="text-slate-400 font-normal text-[10px]">uds</span></span>
      </div>
    `).join('');
  }
  renderDonut();

  // TABLE DATA
  const productData = [
    { cat: 'FRANCES', color: 'rose', products: [
      { name: 'Bolillo', values: [42, 48, 35, 44, 52, 38, 53] },
      { name: 'Telera', values: [32, 36, 28, 33, 38, 28, 38] },
      { name: 'Baguette', values: [22, 24, 18, 22, 26, 20, 24] }
    ]},
    { cat: 'BIZCOCHO', color: 'amber', products: [
      { name: 'Concha', values: [22, 25, 18, 23, 28, 21, 26] },
      { name: 'Cuernito', values: [16, 18, 14, 17, 21, 16, 20] },
      { name: 'Dona', values: [10, 12, 9, 11, 14, 10, 13] },
      { name: 'Mantecada', values: [7, 8, 6, 8, 10, 7, 9] }
    ]},
    { cat: 'PASTELERIA', color: 'emerald', products: [
      { name: 'Pastel 3 leches', values: [11, 13, 9, 12, 15, 11, 15] },
      { name: 'Pastel chocolate', values: [10, 12, 8, 10, 14, 10, 12] },
      { name: 'Pay limón', values: [9, 11, 8, 10, 13, 9, 11] }
    ]}
  ];

  const colorMap = {
    rose:    { dot: '#dc2626', text: '#be123c', bg: ['#fff1f2', '#ffe4e6', '#fecdd3', '#fda4af'] },
    amber:   { dot: '#d97706', text: '#b45309', bg: ['#fffbeb', '#fef3c7', '#fde68a', '#fcd34d'] },
    emerald: { dot: '#059669', text: '#047857', bg: ['#ecfdf5', '#d1fae5', '#a7f3d0', '#6ee7b7'] }
  };

  function sparkline(values, color) {
    const w = 60, h = 20, pad = 2;
    const innerW = w - 2*pad, innerH = h - 2*pad;
    const max = Math.max(...values);
    const min = Math.min(...values);
    const range = max - min || 1;
    const xS = i => pad + (i / (values.length - 1)) * innerW;
    const yS = v => pad + (1 - (v - min) / range) * innerH;
    const path = values.map((v, i) => `${i === 0 ? 'M' : 'L'} ${xS(i).toFixed(1)} ${yS(v).toFixed(1)}`).join(' ');
    return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}"><path d="${path}" fill="none" stroke="${color}" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>`;
  }

  function renderTable(filter = '') {
    const f = filter.toLowerCase().trim();
    let html = '';
    let totalRows = 0;
    productData.forEach(group => {
      const c = colorMap[group.color];
      const matching = group.products.filter(p => !f || p.name.toLowerCase().includes(f));
      if (matching.length === 0) return;
      html += `<tr><td colspan="10" class="pt-3 pb-1.5"><span class="text-[10px] font-bold tracking-widest" style="color:${c.text}">${group.cat}</span></td></tr>`;
      matching.forEach(p => {
        const max = Math.max(...p.values);
        const total = p.values.reduce((s, v) => s + v, 0);
        html += `<tr class="hover:bg-slate-50 transition-colors">`;
        html += `<td class="py-1.5 px-3"><div class="flex items-center gap-2"><span class="w-1.5 h-1.5 rounded-full flex-shrink-0" style="background:${c.dot}"></span><span class="text-slate-700 whitespace-nowrap">${p.name}</span></div></td>`;
        p.values.forEach(v => {
          const ratio = v / max;
          let bg = c.bg[0];
          if (ratio > 0.85) bg = c.bg[3];
          else if (ratio > 0.6) bg = c.bg[2];
          else if (ratio > 0.4) bg = c.bg[1];
          const isMax = v === max;
          html += `<td class="text-center py-1.5 px-2"><span class="inline-block px-2.5 py-0.5 rounded ${isMax ? 'font-bold' : 'font-normal'} text-slate-700 min-w-[36px]" style="background:${bg}">${v}</span></td>`;
        });
        html += `<td class="text-center py-1.5 px-3 font-bold text-slate-900" style="font-family:'JetBrains Mono',monospace">${total}</td>`;
        html += `<td class="text-center py-1.5 px-3">${sparkline(p.values, c.dot)}</td>`;
        html += `</tr>`;
        totalRows++;
      });
    });
    if (totalRows === 0) {
      html = `<tr><td colspan="10" class="text-center py-10 text-slate-400 text-xs">No se encontraron productos que coincidan con "<span class="text-slate-700 font-medium">${filter}</span>"</td></tr>`;
    }
    document.getElementById('productTable').innerHTML = html;
  }
  renderTable();

  document.getElementById('searchInput').addEventListener('input', e => renderTable(e.target.value));

  // TABS
  const tabInactive = 'tab-btn text-slate-500 hover:text-slate-700 pb-3 -mb-px text-sm font-medium flex items-center gap-2 transition';
  const tabActive = 'tab-btn text-rose-600 border-b-2 border-rose-500 pb-3 -mb-px text-sm font-semibold flex items-center gap-2 transition';
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const tab = btn.dataset.tab;
      document.querySelectorAll('.tab-btn').forEach(b => b.className = tabInactive);
      btn.className = tabActive;
      document.getElementById('tab-comportamiento').classList.toggle('hidden', tab !== 'comportamiento');
      document.getElementById('tab-registro').classList.toggle('hidden', tab !== 'registro');
      if (tab === 'registro') renderRegistro();
    });
  });

  function renderRegistro() {
    const days = ['VIE 30', 'SÁB 31', 'DOM 01', 'LUN 02', 'MAR 03', 'MIÉ 04', 'JUE 05'];
    const html = days.map((d, i) => {
      const total = productData.flatMap(g => g.products).reduce((s, p) => s + p.values[i], 0);
      const isHigh = total > 180;
      return `<div class="flex items-center justify-between p-3 border border-slate-100 rounded-lg hover:bg-slate-50 transition">
        <div class="flex items-center gap-3">
          <div class="w-11 h-11 rounded-lg ${isHigh ? 'bg-rose-100' : 'bg-emerald-100'} flex items-center justify-center">
            <span class="text-sm font-bold ${isHigh ? 'text-rose-600' : 'text-emerald-600'}" style="font-family:'JetBrains Mono',monospace">${total}</span>
          </div>
          <div>
            <div class="text-sm font-semibold text-slate-900">${d}</div>
            <div class="text-[11px] text-slate-500">${isHigh ? 'Día de alta merma · Revisar producción' : 'Merma controlada dentro del objetivo'}</div>
          </div>
        </div>
        <div class="text-right">
          <div class="text-[10px] text-slate-400 uppercase tracking-wider font-bold">3 categorías</div>
          <div class="text-xs ${isHigh ? 'text-rose-600' : 'text-emerald-600'} font-semibold">${(total / 6184 * 100).toFixed(1)}% del mes</div>
        </div>
      </div>`;
    }).join('');
    document.getElementById('registroList').innerHTML = html;
  }
})();
</script>
